export type KualaLumpurLocationFilter =
  | "KL City"
  | "Mont Kiara & Hartamas"
  | "Ampang & East"
  | "Subang & West"
  | "South KL"
  | "Other KL";

export function getKualaLumpurLocationFilter(area: string): KualaLumpurLocationFilter {
  const a = area.toLowerCase();
  if (a.includes("klcc") || a.includes("bukit bintang") || a.includes("kl city") || a.includes("kuala lumpur city") || a.includes("bangsar") || a.includes("mid valley") || a.includes("sentul") || a.includes("cheras") || a.includes("setapak")) return "KL City";
  if (a.includes("mont kiara") || a.includes("hartamas") || a.includes("desa park") || a.includes("kepong") || a.includes("segambut") || a.includes("damansara heights") || a.includes("ttdi")) return "Mont Kiara & Hartamas";
  if (a.includes("ampang") || a.includes("ukay") || a.includes("ulu kelang") || a.includes("wangsa maju") || a.includes("melawati") || a.includes("gombak")) return "Ampang & East";
  if (a.includes("subang") || a.includes("petaling") || a.includes("shah alam") || a.includes("kelana") || a.includes("usj") || a.includes("puchong") || a.includes("damansara") || a.includes("kota damansara") || a.includes("tropicana") || a.includes("ara damansara") || a.includes("mutiara damansara")) return "Subang & West";
  if (a.includes("putrajaya") || a.includes("cyberjaya") || a.includes("kajang") || a.includes("semenyih") || a.includes("bangi") || a.includes("serdang") || a.includes("south")) return "South KL";
  return "Other KL";
}

